import{_ as s,o as t,c as a,ai as n}from"./chunks/framework.B2X4_Pzw.js";const u=JSON.parse('{"title":"REPL","description":"","frontmatter":{},"headers":[],"relativePath":"modes/repl.md","filePath":"modes/repl.md","rawMarkdown":"# REPL\\n\\nThe default mode when you run `ra` without a prompt. Full interactive sessions with tool use, file attachments, and session history.\\n\\n```bash\\nra\\n```\\n\\nYou get a `›` prompt. Type a message and ra streams the response, runs tools as the model requests, and saves the conversation automatically.\\n\\n## Commands\\n\\n| Command | Description |\\n|---------|-------------|\\n| `/clear` | Clear history and start a fresh session |\\n| `/resume <session-id>` | Load and continue a previous session |\\n| `/skill <name>` | Activate a skill for the next message |\\n| `/skill-run <skill> <script>` | Run a skill script and attach output to the next message |\\n| `/skill-ref <skill> <file>` | Load a skill reference into context |\\n| `/attach <path>` | Attach a file to the next message |\\n| `/context` | Show discovered context files |\\n| `/memories [n]` | Show stored memories (default: last 20) |\\n| `/forget <query>` | Delete memories matching a search query |\\n\\n## Example session\\n\\n```\\nra\\n› How does the auth module work?\\n› /skill code-review\\n› Review the login handler for security issues\\n› /attach src/auth.ts\\n› What changes would you make to this file?\\n› /resume abc-123           # resume a previous session\\n› /clear                    # start fresh\\n```\\n\\n## Sessions\\n\\nConversations are saved automatically after each turn. Resume with `/resume` inside the REPL, or start in a resumed state from the shell:\\n\\n```bash\\nra --resume abc-123\\n```\\n\\nSessions are pruned automatically after the configured retention period. See [Sessions](/core/sessions) for configuration.\\n\\n## Tips\\n\\n- Use `/attach` to give the model context from files mid-conversation. See [File Attachments](/core/file-attachments) for supported formats.\\n- Use `/skill` to switch the model\'s behavior on the fly without restarting. See [Skills](/skills/) for available skills.\\n- Thinking output streams in real time when `--thinking` is enabled — watch the model reason before responding.\\n- Pipe content in: `cat file.txt | ra` auto-switches to CLI mode, but `ra` without input starts the REPL.\\n\\n## See also\\n\\n- [CLI](/modes/cli) — for one-shot, non-interactive usage\\n- [Sessions](/core/sessions) — session persistence and storage\\n- [Skills](/skills/) — creating and using skills\\n"}'),i={name:"modes/repl.md"};function o(r,e,l,d,h,c){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="repl" tabindex="-1">REPL <a class="header-anchor" href="#repl" aria-label="Permalink to &quot;REPL&quot;">​</a></h1><p>The default mode when you run <code>ra</code> without a prompt. Full interactive sessions with tool use, file attachments, and session history.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span></span></code></pre></div><p>You get a <code>›</code> prompt. Type a message and ra streams the response, runs tools as the model requests, and saves the conversation automatically.</p><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/clear</code></td><td>Clear history and start a fresh session</td></tr><tr><td><code>/resume &lt;session-id&gt;</code></td><td>Load and continue a previous session</td></tr><tr><td><code>/skill &lt;name&gt;</code></td><td>Activate a skill for the next message</td></tr><tr><td><code>/skill-run &lt;skill&gt; &lt;script&gt;</code></td><td>Run a skill script and attach output to the next message</td></tr><tr><td><code>/skill-ref &lt;skill&gt; &lt;file&gt;</code></td><td>Load a skill reference into context</td></tr><tr><td><code>/attach &lt;path&gt;</code></td><td>Attach a file to the next message</td></tr><tr><td><code>/context</code></td><td>Show discovered context files</td></tr><tr><td><code>/memories [n]</code></td><td>Show stored memories (default: last 20)</td></tr><tr><td><code>/forget &lt;query&gt;</code></td><td>Delete memories matching a search query</td></tr></tbody></table><h2 id="example-session" tabindex="-1">Example session <a class="header-anchor" href="#example-session" aria-label="Permalink to &quot;Example session&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ra</span></span>
<span class="line"><span>› How does the auth module work?</span></span>
<span class="line"><span>› /skill code-review</span></span>
<span class="line"><span>› Review the login handler for security issues</span></span>
<span class="line"><span>› /attach src/auth.ts</span></span>
<span class="line"><span>› What changes would you make to this file?</span></span>
<span class="line"><span>› /resume abc-123           # resume a previous session</span></span>
<span class="line"><span>› /clear                    # start fresh</span></span></code></pre></div><h2 id="sessions" tabindex="-1">Sessions <a class="header-anchor" href="#sessions" aria-label="Permalink to &quot;Sessions&quot;">​</a></h2><p>Conversations are saved automatically after each turn. Resume with <code>/resume</code> inside the REPL, or start in a resumed state from the shell:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --resume</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> abc-123</span></span></code></pre></div><p>Sessions are pruned automatically after the configured retention period. See <a href="/ra/core/sessions.html">Sessions</a> for configuration.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use <code>/attach</code> to give the model context from files mid-conversation. See <a href="/ra/core/file-attachments.html">File Attachments</a> for supported formats.</li><li>Use <code>/skill</code> to switch the model&#39;s behavior on the fly without restarting. See <a href="/ra/skills/">Skills</a> for available skills.</li><li>Thinking output streams in real time when <code>--thinking</code> is enabled — watch the model reason before responding.</li><li>Pipe content in: <code>cat file.txt | ra</code> auto-switches to CLI mode, but <code>ra</code> without input starts the REPL.</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/ra/modes/cli.html">CLI</a> — for one-shot, non-interactive usage</li><li><a href="/ra/core/sessions.html">Sessions</a> — session persistence and storage</li><li><a href="/ra/skills/">Skills</a> — creating and using skills</li></ul>`,16)])])}const m=s(i,[["render",o]]);export{u as __pageData,m as default};
